+    private final class ClaudeScanState {
+        var cache: CostUsageCache
+        var rootCache: [String: Int64]
+        var touched: Set<String>
+
+        init(cache: CostUsageCache) {
+            self.cache = cache
+            self.rootCache = cache.roots ?? [:]
+            self.touched = []
+        }
+    }
