+                let size = (attrs[.size] as? NSNumber)?.int64Value ?? 0
+                if size <= 0 { continue }
+                let mtime = (attrs[.modificationDate] as? Date)?.timeIntervalSince1970 ?? 0
+                let mtimeMs = Int64(mtime * 1000)
